  }
  const min = minPriceValue.value
  const max = maxPriceValue.value
  if (!min || !max || max <= min) {
    return 62
  }
  const spread = max - min
  const base = Math.round((spread / max) * 100)
  return Math.max(24, Math.min(88, base + 38))
})

